    `assets/base-defense/Png/Enemy/Enemy01/GetBio_Walk/skeleton-GetBio_walk_${i}.png`);
}
// 敌人死亡：帧编号 5~47（共43帧）
for (let i = 5; i <= 47; i++) {
  this.load.image(`enemy_death_${i}`,
    `assets/base-defense/Png/Enemy/Enemy01/Death/skeleton-Death_${i}.png`);
}
```

---

### 三、动画注册（create() 中）

```javascript
// 箭塔射击（帧率20，循环）
this.anims.create({
  key: 'arrow_tower_shoot',
  frames: Array.from({length:10}, (_,i) => ({ key: `arrow_tower_shoot_${i+5}` })),
  frameRate: 20, repeat: -1
});
// 炮塔射击（帧率8，循环）
this.anims.create({
  key: 'cannon_tower_shoot',
  frames: Array.from({length:10}, (_,i) => ({ key: `cannon_tower_shoot_${i}` })),
  frameRate: 8, repeat: -1
});
// 敌人行走（帧率15，循环）
this.anims.create({
  key: 'enemy_walk',
  frames: Array.from({length:25}, (_,i) => ({ key: `enemy_walk_${i}` })),
  frameRate: 15, repeat: -1
});
// 敌人死亡（帧率20，播放一次）
this.anims.create({
  key: 'enemy_death',
  frames: Array.from({length:43}, (_,i) => ({ key: `enemy_death_${i+5}` })),
  frameRate: 20, repeat: 0
});
```

---

### 四、防御塔参数建议

| 塔类型 | Phaser key（首帧） | 射程 | 攻击间隔 | 伤害 | 造价 |
|---|---|---|---|---|---|
| 箭塔 | `arrow_tower_shoot_5` | 150px | 500ms | 10 | 50金币 |
| 炮塔 | `cannon_tower_shoot_0` | 220px | 1500ms | 40 | 100金币 |

---

### 五、注意事项

1. **帧序列起始帧不同**：箭塔从帧5开始（`skeleton-Shoot_5.png`），炮塔从帧0开始，敌人死亡从帧5开始，加载循环的起止值需严格按 `frame_sequence_info` 中的 `start/end` 设置。
2. **子弹文件名拼写**：原始文件名为 `Bulet08.png`（单 l），注意不要写成 `Bullet`。
3. **UI 按钮交互**：所有 UI 图片需调用 `.setInteractive()` 后才能响应 `pointerdown` 事件。
4. **右键卖塔**：需在 Phaser 游戏配置中开启 `input.mouse.preventDefaultDown: false` 以支持右键事件。
5. **完整加载代码和 usage_snippets** 已写入 manifest.json 的 `phaser_config.load_code`、`phaser_config.anim_create_code`、`phaser_config.usage_snippets` 字段，可直接复制使用。

