import { create } from 'zustand';

export type TowerType = 'arrow' | 'cannon' | null;

interface GameState {
  hp: number;
  gold: number;
  wave: number;
  maxWaves: number;
  status: 'menu' | 'playing' | 'won' | 'lost';
  selectedTower: TowerType;

  setHp: (hp: number) => void;
  addGold: (amount: number) => void;
  setWave: (wave: number) => void;
  setStatus: (status: 'menu' | 'playing' | 'won' | 'lost') => void;
  setSelectedTower: (tower: TowerType) => void;
  resetGame: () => void;
}

export const useGameStore = create<GameState>((set) => ({
  hp: 10,
  gold: 100,
  wave: 0,
  maxWaves: 5,
  status: 'menu',
  selectedTower: null,

  setHp: (hp) => set({ hp }),
  addGold: (amount) => set((state) => ({ gold: state.gold + amount })),
  setWave: (wave) => set({ wave }),
  setStatus: (status) => set({ status }),
  setSelectedTower: (tower) => set({ selectedTower: tower }),
  resetGame: () => set({ hp: 10, gold: 100, wave: 0, status: 'playing', selectedTower: null }),
}));

import Phaser from 'phaser';

export const loadAssets = (scene: Phaser.Scene) => {
  scene.load.on('loaderror', (file: any) => {
    console.error('Error loading asset:', file.key);
    const g = scene.add.graphics();
    const w = scene.game.config.width as number;
    const h = scene.game.config.height as number;
    g.fillGradientStyle(0x667788, 0x334455, 0x334455, 0x667788);
    g.fillRect(0,0,w,h);
    g.generateTexture(file.key, w, h);
    g.destroy();
  });

  // --- 背景 ---
  scene.load.image('bg_main', 'assets/base-defense/Png/Backgrounds/Bg02/Repeated.png');
  // --- 基地建筑 ---
  scene.load.image('base_building', 'assets/base-defense/Png/Base/13.png');
  // --- 箭塔帧序列（10帧，帧编号5~14）---
  for (let i = 5; i <= 14; i++) { scene.load.image(`arrow_tower_shoot_${i}`, `assets/base-defense/Png/Weapons/01/skeleton-Shoot_${i}.png`); }
  // --- 炮塔帧序列（10帧，帧编号0~9）---
  for (let i = 0; i <= 9; i++) { scene.load.image(`cannon_tower_shoot_${i}`, `assets/base-defense/Png/Weapons/05/skeleton-Shoot_${i}.png`); }
  // --- 敌人行走帧序列（25帧，帧编号0~24）---
  for (let i = 0; i <= 24; i++) { scene.load.image(`enemy_walk_${i}`, `assets/base-defense/Png/Enemy/Enemy01/GetBio_Walk/skeleton-GetBio_walk_${i}.png`); }
  // --- 敌人死亡帧序列（43帧，帧编号5~47）---
  for (let i = 5; i <= 47; i++) { scene.load.image(`enemy_death_${i}`, `assets/base-defense/Png/Enemy/Enemy01/Death/skeleton-Death_${i}.png`); }
  // --- 子弹 ---
  scene.load.image('bullet_arrow', 'assets/base-defense/Png/Projectile/Bulet08.png');
  scene.load.image('bullet_cannon', 'assets/base-defense/Png/Projectile/Bulet10.png');
  // --- 命中特效帧序列（14帧，帧编号0~13）---
  for (let i = 0; i <= 13; i++) { scene.load.image(`hit_fx_${i}`, `assets/base-defense/Png/Collision_Fx/Fx01/skeleton-animation_${i}.png`); }
  // --- 射击特效帧序列（10帧，帧编号0~9）---
  for (let i = 0; i <= 9; i++) { scene.load.image(`shoot_fx_${i}`, `assets/base-defense/Png/Shoot_FX/Fx1/skeleton-animation_${i}.png`); }
  // --- UI 元素 ---
  scene.load.image('ui_coin_icon',  'assets/base-defense/Png/User_Interface/CoinIcon.png');
  scene.load.image('ui_coin_bar',   'assets/base-defense/Png/User_Interface/CoinBar.png');
  scene.load.image('ui_hp_icon',    'assets/base-defense/Png/User_Interface/ShieldIcon.png');
  scene.load.image('ui_pause_btn',  'assets/base-defense/Png/User_Interface/PauseBtn.png');
  scene.load.image('ui_green_btn',  'assets/base-defense/Png/User_Interface/GreenBtn.png');
  scene.load.image('ui_orange_btn', 'assets/base-defense/Png/User_Interface/OrangeBtn.png');
  scene.load.image('ui_won_game',   'assets/base-defense/Png/User_Interface/WonGame.png');
  scene.load.image('ui_lost_game',  'assets/base-defense/Png/User_Interface/LostGame.png');
  scene.load.image('ui_game_title', 'assets/base-defense/Png/User_Interface/GameTitle.png');
  scene.load.image('ui_enemy_hp',   'assets/base-defense/Png/User_Interface/EnemyHpBar1.png');
  scene.load.image('ui_panel_bg',   'assets/base-defense/Png/User_Interface/BgPopUp.png');
};

export const createAnimations = (scene: Phaser.Scene) => {
  // 箭塔射击动画（帧率20，循环）
  scene.anims.create({ key: 'arrow_tower_shoot', frames: Array.from({length:10},(_,i)=>({key:`arrow_tower_shoot_${i+5}`})), frameRate: 20, repeat: -1 });
  // 炮塔射击动画（帧率8，循环）
  scene.anims.create({ key: 'cannon_tower_shoot', frames: Array.from({length:10},(_,i)=>({key:`cannon_tower_shoot_${i}`})), frameRate: 8, repeat: -1 });
  // 敌人行走动画（帧率15，循环）
  scene.anims.create({ key: 'enemy_walk', frames: Array.from({length:25},(_,i)=>({key:`enemy_walk_${i}`})), frameRate: 15, repeat: -1 });
  // 敌人死亡动画（帧率20，播放一次）
  scene.anims.create({ key: 'enemy_death', frames: Array.from({length:43},(_,i)=>({key:`enemy_death_${i+5}`})), frameRate: 20, repeat: 0 });
  // 命中特效动画（帧率24，播放一次）
  scene.anims.create({ key: 'hit_fx', frames: Array.from({length:14},(_,i)=>({key:`hit_fx_${i}`})), frameRate: 24, repeat: 0 });
  // 射击特效动画（帧率24，播放一次）
  scene.anims.create({ key: 'shoot_fx', frames: Array.from({length:10},(_,i)=>({key:`shoot_fx_${i}`})), frameRate: 24, repeat: 0 });
};

